class TaskManager:
    def __init__(self):
        self.tasks = {}  # Dictionary to store tasks and their completion status
        self.dependencies = {}  # Dictionary to store task dependencies

    def add_task(self, task_id, dependencies=None):
        if dependencies is None:
            dependencies = []
        if task_id in self.tasks:
            print(f"Task {task_id} already exists.")
        else:
            self.tasks[task_id] = False  # Initialize task as not completed
            self.dependencies[task_id] = dependencies

    def can_execute(self, task_id):
        if task_id not in self.tasks:
            print(f"Task {task_id} does not exist.")
            return False
        if self.tasks[task_id]:
            return True
        if not self.dependencies[task_id]:
            self.tasks[task_id] = True
            return True
        for dependency in self.dependencies[task_id]:
            if not self.can_execute(dependency):
                return False
        self.tasks[task_id] = True
        return True

    def complete_task(self, task_id):
        if task_id in self.tasks:
            self.tasks[task_id] = True  # Mark the task as completed
        else:
            print(f"Task {task_id} does not exist.")

